mapper.select:
SELECT DISTINCT H.* FROM ( SELECT '0' AS CHK, T.TARGET_ID, T.NAME AS AGENT_NAME, IF ( PLATFORM = 'Remote Access Only', '1', EXPORT_SET(A.AGENT_CONNECTED,'1','0','',1) ) AS AGENT_CONNECTED, #A.AGENT_CONNECTED, A.AGENT_VERSION, A.AGENT_PLATFORM, A.AGENT_PLATFORM_COMPATIBILITY, EXPORT_SET(A.AGENT_VERIFIED,'1','0','',1) AS AGENT_VERIFIED, A.AGENT_USER, A.AGENT_CPU, A.AGENT_CORES, A.AGENT_BOOT, A.AGENT_RAM, A.AGENT_STARTED, A.AGENT_CONNECTED_IP, T.SEARCH_TIME, DATE_FORMAT(FROM_UNIXTIME(t.search_time), '%Y-%m-%d %h:%i:%s' ) as SEARCH_DATETIME, DATE_FORMAT(t.regdate, '%Y-%m-%d %h:%i:%s' ) as REGDATE, IFNULL((SELECT COUNT(*) FROM PI_FIND F WHERE F.GROUP_ID = T.GROUP_ID AND F.TARGET_ID = T.TARGET_ID),0) AS FIND_CNT FROM PI_TARGETS T LEFT OUTER JOIN PI_AGENTS A ON T.NAME = A.AGENT_NAME AND T.AP_NO = A.AP_NO AND A.AGENT_USE = 'Y'
, PI_TARGET_USER U
WHERE 1 = 1
AND T.TARGET_ID = U.TARGET_ID AND U.USER_NO = #{user_no}
AND T.TARGET_USE = 'Y'
AND T.GROUP_IDX = #{group_id}
AND T.GROUP_IDX IS NULL
AND T.NAME REGEXP #{host}
) H ORDER BY H.AGENT_NAME

	UPDATE PI_TARGET_GROUP SET

