mapper.select:
SELECT H.TARGET_ID, H.AGENT_USE, CASE WHEN AP_NO = 1 THEN CONCAT(H.AGENT_VERSION, '-', '유통') WHEN AP_NO = 2 THEN CONCAT(H.AGENT_VERSION, '-', 'OA') WHEN AP_NO = 3 THEN CONCAT(H.AGENT_VERSION, '-', 'VDI') END AS AGENT_VERSION, H.PLATFORM, H.AGENT_BOOT, H.AGENT_STARTED, DATE_FORMAT(H.AGENT_CONNECTED_START_DT,'%Y-%m-%d') AS AGENT_CONNECTED_START_DT, IFNULL(H.AGENT_CONNECTED_END_DT, H.AGENT_CONNECTED_START_DT) AS AGENT_CONNECTED_END_DT, H.REGDATE, H.AP_NO, H.GROUP_NAME, H.NAME, H.TARGET_USE, H.AGENT_CONNECTED, H.AGENT_CONNECTED_IP, H.USER_NO, H.USER_NAME, H.USER_NM, H.TEAM_NM, H.SERVICE_USER_NO, H.SERVICE_USER_NM, H.SERVICE_USER_NAME, H.SERVICE_TEAM_NM, (SELECT P.POLICY_NAME FROM PI_SCAN_POLICY P WHERE P.IDX = H.POLICY_ID) AS POLICY_NM, H.POLICY_ID, IFNULL((SELECT P.ENABLED FROM PI_SCAN_POLICY P WHERE P.IDX = H.POLICY_ID), 2) AS ENABLE FROM (SELECT T.TARGET_ID, AGENT_USE AS AGENT_USE, AGENT_VERSION, DATE_FORMAT(FROM_UNIXTIME(A.AGENT_BOOT),'%Y-%m-%d %H:%i') AS AGENT_BOOT, DATE_FORMAT(FROM_UNIXTIME(A.AGENT_STARTED),'%Y-%m-%d %H:%i') AS AGENT_STARTED, DATE_FORMAT(A.AGENT_CONNECTED_START_DT,'%Y-%m-%d %H:%i') AS AGENT_CONNECTED_START_DT, DATE_FORMAT(A.AGENT_CONNECTED_END_DT,'%Y-%m-%d %H:%i') AS AGENT_CONNECTED_END_DT, DATE_FORMAT(A.REGDATE,'%Y-%m-%d %H:%i') AS REGDATE, T.AP_NO, T.PLATFORM, # IFNULL(CASE WHEN T.AP_NO = 0 THEN (SELECT G.NAME FROM pi_target_group G WHERE G.IDX = T.GROUP_IDX) ELSE UG.TEAM_NAME END, '') AS GROUP_NAME, AP.HOSTNAME AS GROUP_NAME, T.NAME AS FULL_NAME, T.TARGET_USE, SUBSTRING_INDEX(T.NAME, '.', 1) AS HOST_NAME, SUBSTRING_INDEX(SUBSTRING_INDEX(T.NAME, '.', -2), '.', 1) AS NAME, SUBSTRING_INDEX(T.NAME, '.', -1) AS SERIAL, IF(A.AGENT_CONNECTED = '1', '연결', '미 연결') AS AGENT_CONNECTED, A.AGENT_CONNECTED_IP, U.USER_NO, CONCAT(U.USER_NAME, '(', U.SOSOK, ')') AS USER_NAME, U.USER_NAME AS USER_NM, U.SOSOK AS TEAM_NM,
(SELECT GROUP_CONCAT(TSU.USER_NO) FROM PI_TARGET_SERVICE_USER TSU WHERE T.TARGET_ID = TSU.TARGET_ID AND T.AP_NO = TSU.AP_NO) AS SERVICE_USER_NO, (SELECT (CASE WHEN COUNT(TSU.USER_NO) > 1 THEN CONCAT(U.USER_NAME,'(', U.SOSOK ,')' ,' 외 ',COUNT(TSU.USER_NO)-1, '명') ELSE CONCAT(U.USER_NAME,'(', U.SOSOK ,')') END) FROM PI_TARGET_SERVICE_USER TSU, pi_user U WHERE T.TARGET_ID = TSU.TARGET_ID AND T.AP_NO = TSU.AP_NO AND TSU.USER_NO = U.USER_NO ORDER BY U.USER_NO, U.USER_NAME) AS SERVICE_USER_NAME, (SELECT (CASE WHEN COUNT(TSU.USER_NO) > 1 THEN CONCAT(U.USER_NAME ,' 외 ',COUNT(TSU.USER_NO)-1, '명') ELSE U.USER_NAME END) FROM PI_TARGET_SERVICE_USER TSU, pi_user U WHERE T.TARGET_ID = TSU.TARGET_ID AND T.AP_NO = TSU.AP_NO AND TSU.USER_NO = U.USER_NO ORDER BY U.USER_NO, U.USER_NAME) AS SERVICE_USER_NM, (SELECT (CASE WHEN COUNT(TSU.USER_NO) > 1 THEN U.SOSOK ELSE U.SOSOK END) FROM PI_TARGET_SERVICE_USER TSU, pi_user U WHERE T.TARGET_ID = TSU.TARGET_ID AND T.AP_NO = TSU.AP_NO AND TSU.USER_NO = U.USER_NO ORDER BY U.USER_NO, U.USER_NAME) AS SERVICE_TEAM_NM,
MAX_STS.POLICY_ID FROM pi_ap_server AP, pi_targets T LEFT OUTER JOIN (SELECT ST.TARGET_ID, ST.AP_NO, ST.LOCATION_ID, ST.RECON_SCHEDULE_ID,ST.REGDATE, ST.POLICY_ID, ST.CONFIRM FROM pi_schedule_targets ST, (SELECT STS.TARGET_ID, STS.AP_NO ,MAX(STS.REGDATE) AS REGDATE FROM pi_schedule_targets STS GROUP BY STS.TARGET_ID, STS.AP_NO) STS WHERE STS.TARGET_ID = ST.TARGET_ID AND STS.AP_NO = ST.AP_NO AND STS.REGDATE = ST.REGDATE ) AS MAX_STS ON T.TARGET_ID = MAX_STS.TARGET_ID AND T.AP_NO = MAX_STS.AP_NO LEFT OUTER JOIN pi_agents A ON T.NAME = A.AGENT_NAME AND T.AP_NO = A.AP_NO LEFT OUTER JOIN PI_TARGET_SERVICE_USER SU ON T.TARGET_ID = SU.TARGET_ID AND T.AP_NO = SU.AP_NO LEFT OUTER JOIN PI_TARGET_USER TU ON T.TARGET_ID = TU.TARGET_ID AND T.AP_NO = TU.AP_NO LEFT OUTER JOIN PI_USER U ON U.USER_NO = TU.USER_NO LEFT OUTER JOIN PI_GROUP UG ON U.INSA_CODE = UG.INSA_CODE WHERE 1 = 1
AND TU.USER_NO = #{user_no}
AND TU.USER_NO = #{user_no}
AND T.AP_NO = AP.AP_NO AND AP.IS_SERVER != 1 AND T.TARGET_USE = 'Y' AND (A.AGENT_USE = 'Y' OR A.AGENT_USE IS NULL) ) H WHERE 1 = 1
AND H.USER_NO IS NULL
AND H.USER_NO = #{id}
AND H.NAME = #{name}
AND H.TARGET_ID = #{target_id}
AND H.GROUP_NAME LIKE CONCAT('%', #{groupNm},'%')
AND H.NAME LIKE CONCAT('%',#{hostNm},'%')
AND H.USER_NM LIKE CONCAT('%',#{serviceNm},'%')
AND H.AGENT_CONNECTED_IP LIKE CONCAT('%',#{userIP},'%')
GROUP BY H.TARGET_ID, H.AP_NO ORDER BY H.NAME

